customCSS:
/* Spring Bloom - Cherry Blossom Background */
@import url('https://fonts.googleapis.com/css2?family=Quicksand:wght@300;400;500;600;700&family=Nunito:wght@300;400;600&family=Source+Code+Pro&display=swap');

/* Static floral gradient background */
.cyber-grid {
  background: none;
  animation: none;
}

.cyber-glow {
  background: 
    radial-gradient(ellipse at 20% 20%, rgba(249, 168, 212, 0.12) 0%, transparent 40%),
    radial-gradient(ellipse at 80% 30%, rgba(192, 132, 252, 0.1) 0%, transparent 35%),
    radial-gradient(ellipse at 40% 80%, rgba(134, 239, 172, 0.15) 0%, transparent 45%),
    linear-gradient(180deg, rgba(192, 132, 252, 0.05) 0%, rgba(134, 239, 172, 0.08) 100%);
  animation: none;
}

.cyber-particles { display: none; }

.stat-card {
  border-radius: 16px;
  border: 1px solid rgba(134, 239, 172, 0.2);
}

.stat-card::before {
  background: linear-gradient(135deg, #86efac, #5eead4, #c084fc, #f9a8d4);
}

.stat-card:hover {
  box-shadow: 0 0 25px rgba(134, 239, 172, 0.2);
}

.celebration-title {
  background: linear-gradient(135deg, #86efac, #5eead4, #c084fc, #f9a8d4);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card { border-radius: 16px; }
